def rc(p):
    with open(p,'rb') as f: return max(sum(1 for _ in f)-1,0)
def choose(vals,n,probs=None): return np.random.choice(vals,n,p=(np.array(probs)/np.sum(probs) if probs is not None else None))
def assign_from_groups(codes, groups):
    out=np.empty(len(codes), dtype=int)
    codes_arr=np.asarray(codes)
    for c, vals in groups.items():
        m=(codes_arr==c); out[m]=np.random.choice(vals, m.sum())
    return out
def save(df,name,folder=DIM):
    df.to_csv(folder/name,index=False); print(name,len(df))
def parse_med():
    pat=re.compile(r'^\s*(\d+)\.\s*(.*?)\s*-\s*(.*?)\s*$'); rows=[]
    terms=['antidepressant','serotonin','benzodiazepine','antipsychotic','mood stabilizer','anxiolytic','stimulant','sedative','hypnotic','melatonin','norepinephrine','tricyclic']
    with open(FILES['medtxt'],encoding='utf-8',errors='ignore') as f:
        for line in f:
            m=pat.match(line.strip())
            if not m: continue
            full=m.group(2).strip(); cls=m.group(3).strip(); sm=re.search(r'\((.*?)\)',full); name=re.sub(r'\s*\(.*?\)','',full).strip(); strength=sm.group(1) if sm else 'Unknown'; flag=int(any(t in cls.lower() for t in terms))
            rows.append([len(rows)+1,int(m.group(1)),name,full,strength,cls,flag,1])
    df=pd.DataFrame(rows,columns=['MedicationKey','SourceMedicationNumber','MedicationName','MedicationFullDescription','Strength','TherapeuticClass','MentalHealthMedicationFlag','ActiveFlag']).drop_duplicates(['MedicationName','Strength','TherapeuticClass']).reset_index(drop=True); df['MedicationKey']=np.arange(1,len(df)+1); return df

