def docs_zip():
    counts=[]
    for folder in [DIM,FACT]:
        for f in folder.glob('*.csv'): counts.append({'TableName':f.stem,'RowCount':rc(f),'ColumnCount':len(pd.read_csv(f,nrows=0).columns)})
    pd.DataFrame(counts).to_csv(QUAL/'Generated_Table_Row_Counts.csv',index=False)
    pd.DataFrame([{'SourceFile':v.name,'RowCount':rc(v) if v.suffix=='.csv' else sum(1 for line in open(v,encoding='utf-8',errors='ignore') if line.strip())} for v in FILES.values()]).to_csv(QUAL/'Source_Row_Counts.csv',index=False)
    lines=['-- LYRA WELLBEING ANALYTICS SNOWFLAKE DDL','CREATE DATABASE IF NOT EXISTS LYRA_ANALYTICS;','CREATE SCHEMA IF NOT EXISTS LYRA_ANALYTICS.DIM;','CREATE SCHEMA IF NOT EXISTS LYRA_ANALYTICS.FACT;','']
    for folder,schema in [(DIM,'DIM'),(FACT,'FACT')]:
        for f in sorted(folder.glob('*.csv')):
            df=pd.read_csv(f,nrows=25,low_memory=False); lines.append(f'CREATE OR REPLACE TABLE LYRA_ANALYTICS.{schema}.{f.stem.upper()} ('); col=[]
            for c in df.columns:
                d=str(df[c].dtype).lower(); typ='NUMBER(38,0)' if 'int' in d else ('NUMBER(18,4)' if 'float' in d else ('TIMESTAMP_NTZ' if 'datetime' in d else 'VARCHAR'))
                col.append(f'    {c.upper()} {typ}')
            lines.append(',\n'.join(col)); lines.append(');\n')
    (SQL/'01_Create_Lyra_Snowflake_Tables.sql').write_text('\n'.join(lines),encoding='utf-8')
    md='# Lyra Wellbeing Analytics Additional Data Model\n\nThe pack adds Lyra-relevant mental health, employee wellbeing, client-company, country, currency, consent, SCD Type 2 and digital engagement data to your supplied healthcare files.\n\n## Core Tables\n\n| Table | Rows | Purpose |\n|---|---:|---|\n'
    for r in counts: md+=f"| {r['TableName']} | {r['RowCount']:,} | Generated/enriched analytics table |\n"
    md+='''\n## ERD\n```text\nDimDate ─┬─ FactCounsellingSessions ─ DimServiceType ─ DimIssueCategory\n         │             ├ DimClientCompany ─ DimCountry ─ DimCurrency\n         │             ├ DimFacilityGeography\n         │             ├ DimCounsellor\n         │             ├ DimEmployee_SCD2\n         │             └ DimConsent_SCD2\n         ├─ FactMedicationSales ─ DimMedication\n         ├─ FactDigitalEngagement\n         └─ FactPatientExperience\n```\n\nThis design is suitable for Snowflake, dbt, Snowpark, Tableau and Power BI demonstration work.\n'''
    (DOC/'Data_Model_and_Project_Guide.md').write_text(md,encoding='utf-8')
    shutil.copy2(__file__,CODE/'build_project_chunked.py')
    zpath=BASE/'Lyra_Analytics_Project.zip'
    if zpath.exists(): zpath.unlink()
    with zipfile.ZipFile(zpath,'w',zipfile.ZIP_DEFLATED,compresslevel=6) as z:
        for f in PROJ.rglob('*'):
            if f.is_file(): z.write(f,f.relative_to(PROJ.parent))
    print('ZIP_DONE',zpath,zpath.stat().st_size/1024/1024)

def main():
    setup(); fac=facility(); sessions(fac); exp(); med_sales(); digital(); scd(); docs_zip()
if __name__=='__main__': main()
